// ---- Extract YouTube Video ID from URL or plain ID ----
const rawLink = item.json['Link do vídeo do YouTube'] || '';
let videoId = rawLink.trim();

// Try to extract ID from various YouTube URL formats
const patterns = [
  /[?&]v=([a-zA-Z0-9_-]{11})/,           // youtube.com/watch?v=ID
  /youtu\.be\/([a-zA-Z0-9_-]{11})/,        // youtu.be/ID
  /\/embed\/([a-zA-Z0-9_-]{11})/,          // youtube.com/embed/ID
  /\/shorts\/([a-zA-Z0-9_-]{11})/,         // youtube.com/shorts/ID
  /\/live\/([a-zA-Z0-9_-]{11})/,           // youtube.com/live/ID
];
for (const pat of patterns) {
  const m = rawLink.match(pat);
  if (m) { videoId = m[1]; break; }
}
// If it's already an 11-char ID, keep it
if (/^[a-zA-Z0-9_-]{11}$/.test(videoId)) {
  // OK
} else if (videoId.length > 11) {
  // Last resort: try to find 11-char segment
  const fallback = videoId.match(/([a-zA-Z0-9_-]{11})/);
  if (fallback) videoId = fallback[1];
}

// ---- Combine date + time into ISO 8601 ----
const rawDate = item.json['Data da primeira publicação'] || new Date().toISOString().slice(0, 10);
const rawTime = item.json['Horário de publicação (HH:MM, UTC)'] || '08:00';
const timeParts = rawTime.trim().match(/(\d{1,2}):(\d{2})/);
const hh = timeParts ? timeParts[1].padStart(2, '0') : '08';
const mm = timeParts ? timeParts[2] : '00';
const firstPublicationAt = `${rawDate}T${hh}:${mm}:00Z`;

// ---- Map duration dropdown to min/max ----
const durSelection = item.json['Duração média dos Shorts'] || 'Livre';
const durMap = {
  'Livre': { min: 45, max: 180 },
  '15-30': { min: 15, max: 30 },
  '30-45': { min: 30, max: 45 },
  '45-59': { min: 45, max: 59 },
  '60-90': { min: 60, max: 90 },
};
let targetDurMin = 45, targetDurMax = 180; // default = livre
for (const [key, val] of Object.entries(durMap)) {
  if (durSelection.includes(key)) { targetDurMin = val.min; targetDurMax = val.max; break; }
}

// ---- Map caption style dropdown to preset key ----
const styleSelection = item.json['Estilo das legendas'] || 'CapCut Bold';
const styleMap = {
  'CapCut Bold': 'capcut-bold',
  'Clean Minimal': 'clean-minimal',
  'Neon Glow': 'neon-glow',
  'MrBeast': 'mrbeast',
  'Podcast': 'podcast',
  'Karaoke': 'karaoke',
};
let captionPreset = 'capcut-bold';
for (const [key, val] of Object.entries(styleMap)) {
  if (styleSelection.includes(key)) { captionPreset = val; break; }
}

// ---- Map niche dropdown to clean string ----
const nicheRaw = item.json['Nicho do canal'] || 'tecnologia e internet';
// Strip emoji prefix if present
const channelNiche = nicheRaw.replace(/^[^a-zA-ZÀ-ú]+/, '').trim() || 'tecnologia e internet';

const targetAudience = item.json['Público-alvo (opcional)'] || '';

return {
  json: {
    videoSource: 'youtube',
    videoId,
    firstPublicationAt,
    intervalHours: Number(item.json['Intervalo entre publicações (horas)']) || 6,
    captionPreset,
    targetDurMin,
    targetDurMax,
    channelNiche,
    targetAudience,
  }
};

// Map the caption preset from preparingField into styling format for render
const preset = $('preparingField').item.json.captionPreset || 'capcut-bold';
return { json: { stylingType: 'preset', styling: preset } };

const startDateString = $node["preparingField"].json.firstPublicationAt;
const startDate = new Date(startDateString);
const intervalHours = $node["preparingField"].json.intervalHours;

items.forEach((item, index) => {
  const publishingDate = new Date(startDate.getTime() + index * intervalHours * 60 * 60 * 1000);
  item.json.publicationDate = publishingDate.toISOString();
});

return items;

