// Try to find JSON in the response
let parsed = null;
try {
  // Direct parse
  parsed = JSON.parse(raw);
} catch(e) {
  // Try extracting from markdown code block
  const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (match) {
    try { parsed = JSON.parse(match[1].trim()); } catch(e2) {}
  }
  // Try finding JSON object in text
  if (!parsed) {
    const braceMatch = raw.match(/\{[\s\S]*\}/);
    if (braceMatch) {
      try { parsed = JSON.parse(braceMatch[0]); } catch(e3) {}
    }
  }
}

// Fallback defaults
const output = {
  short_title: parsed?.short_title || 'Short do vídeo',
  short_description: parsed?.short_description || 'Assista ao short completo! #shorts',
  short_tags: parsed?.short_tags || ['shorts', 'youtubeshorts'],
  youtube_category_id: parsed?.youtube_category_id || 22,
};

return { json: { output } };

